import React, { useState } from 'react';
import axios from 'axios';

const App = () => {
  const [numClasses, setNumClasses] = useState(0);
  const [classNames, setClassNames] = useState([]);
  const [imageFiles, setImageFiles] = useState({});

  const handleNumClassesChange = (e) => {
    const value = e.target.value;
    setNumClasses(value);
    setClassNames(Array.from({ length: value }, (_, i) => `Class ${i + 1}`));
  };

  const handleImageChange = (className, e) => {
    const files = e.target.files;
    setImageFiles(prev => ({
      ...prev,
      [className]: files,
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const formData = new FormData();

    for (const className of classNames) {
      if (imageFiles[className]) {
        for (let i = 0; i < imageFiles[className].length; i++) {
          formData.append(`${className}_image`, imageFiles[className][i]);
        }
      }
    }

    try {
      const response = await axios.post('http://localhost:8000/train', formData);
      alert(response.data.message);
    } catch (error) {
      console.error("There was an error!", error);
    }
  };

  return (
    <div>
      <h1>Teachable Machine</h1>
      <form onSubmit={handleSubmit}>
        <label>
          Number of Classes:
          <input type="number" value={numClasses} onChange={handleNumClassesChange} />
        </label>
        {classNames.map((className, index) => (
          <div key={index}>
            <h3>{className}</h3>
            <input 
              type="file" 
              multiple 
              onChange={(e) => handleImageChange(className, e)} 
            />
          </div>
        ))}
        <button type="submit">Train Model</button>
      </form>
    </div>
  );
};

export default App;
